export default ResultDisplay;

import { jsPDF } from 'jspdf';
import 'jspdf-autotable';
import { ProcessedResult, SchoolConfig } from '../types';

// Extend jsPDF for autoTable
declare module 'jspdf' {
  interface jsPDF {
    autoTable: (options: any) => jsPDF;
  }
}

export const generateSinglePDF = async (result: ProcessedResult, config: SchoolConfig) => {
  const doc = new jsPDF({
    orientation: 'portrait',
    unit: 'mm',
    format: 'a4'
  });

  addResultCardToDoc(doc, result, config);
  doc.save(`${result.student.rollNo}_${result.student.name.replace(/\s+/g, '_')}_Result.pdf`);
};

export const generateBulkPDF = async (results: ProcessedResult[], config: SchoolConfig) => {
  const doc = new jsPDF({
    orientation: 'portrait',
    unit: 'mm',
    format: 'a4'
  });

  results.forEach((result, index) => {
    if (index > 0) doc.addPage();
    addResultCardToDoc(doc, result, config);
  });

  doc.save(`${config.name.replace(/\s+/g, '_')}_Full_Results.pdf`);
};

const addResultCardToDoc = (doc: jsPDF, result: ProcessedResult, config: SchoolConfig) => {
  const pageWidth = doc.internal.pageSize.getWidth();

  // -- Header Section --
  doc.setFillColor(245, 248, 255);
  doc.rect(0, 0, pageWidth, 50, 'F');

  doc.setTextColor(30, 64, 175);
  doc.setFont('helvetica', 'bold');
  doc.setFontSize(24);
  doc.text(config.name, pageWidth / 2, 20, { align: 'center' });

  doc.setTextColor(100, 116, 139);
  doc.setFontSize(10);
  doc.setFont('helvetica', 'normal');
  doc.text(config.address, pageWidth / 2, 26, { align: 'center' });
  doc.text(`Contact: ${config.contact}`, pageWidth / 2, 31, { align: 'center' });

  doc.setTextColor(30, 41, 59);
  doc.setFontSize(14);
  doc.setFont('helvetica', 'bold');
  doc.text(config.examType, pageWidth / 2, 42, { align: 'center' });

  // -- Student Information --
  doc.setFontSize(11);
  doc.setTextColor(51, 65, 85);

  const leftCol = 20;
  const rightCol = 110;
  let currentY = 65;

  doc.text('Roll Number:', leftCol, currentY);
  doc.setFont('helvetica', 'bold');
  doc.text(result.student.rollNo, leftCol + 35, currentY);

  doc.setFont('helvetica', 'normal');
  doc.text('Class/Section:', rightCol, currentY);
  doc.setFont('helvetica', 'bold');
  doc.text(`${result.student.class} - ${result.student.section}`, rightCol + 35, currentY);

  currentY += 10;
  doc.setFont('helvetica', 'normal');
  doc.text('Student Name:', leftCol, currentY);
  doc.setFont('helvetica', 'bold');
  doc.text(result.student.name, leftCol + 35, currentY);

  doc.setFont('helvetica', 'normal');
  doc.text('Father Name:', rightCol, currentY);
  doc.setFont('helvetica', 'bold');
  doc.text(result.student.fatherName, rightCol + 35, currentY);

  currentY += 10;
  doc.setFont('helvetica', 'normal');
  doc.text('Academic Year:', leftCol, currentY);
  doc.setFont('helvetica', 'bold');
  doc.text(config.academicYear, leftCol + 35, currentY);

  // -- Marks Table --
  doc.autoTable({
    startY: currentY + 15,
    margin: { left: 20, right: 20 },
    head: [['Subject Name', 'Total Marks', 'Passing Marks', 'Obtained Marks', 'Status']],
    body: result.scores.map(s => [
      s.subjectName,
      s.totalMarks,
      s.passingMarks,
      s.obtainedMarks,
      Number(s.obtainedMarks) >= Number(s.passingMarks) ? 'Pass' : 'Fail'
    ]),
    headStyles: { fillColor: [30, 64, 175], textColor: 255, halign: 'center', fontStyle: 'bold' },
    columnStyles: {
      0: { halign: 'left' },
      1: { halign: 'center' },
      2: { halign: 'center' },
      3: { halign: 'center' },
      4: { halign: 'center' }
    },
    bodyStyles: { textColor: [51, 65, 85] }
  });

  // @ts-ignore
  let finalY = doc.lastAutoTable.finalY + 15;

  // -- Summary Section --
  doc.setFillColor(248, 250, 252);
  doc.rect(20, finalY, pageWidth - 40, 35, 'F');
  doc.setDrawColor(226, 232, 240);
  doc.rect(20, finalY, pageWidth - 40, 35, 'S');

  doc.setTextColor(30, 41, 59);
  doc.setFontSize(10);
  doc.setFont('helvetica', 'normal');

  doc.text('Grand Total:', 30, finalY + 12);
  doc.setFont('helvetica', 'bold');
  doc.text(`${result.summary.totalObtainedMarks} / ${result.summary.totalMaxMarks}`, 60, finalY + 12);

  doc.setFont('helvetica', 'normal');
  doc.text('Percentage:', 30, finalY + 22);
  doc.setFont('helvetica', 'bold');
  doc.text(`${result.summary.percentage}%`, 60, finalY + 22);

  doc.setFont('helvetica', 'normal');
  doc.text('Final Grade:', 110, finalY + 12);
  doc.setFont('helvetica', 'bold');
  doc.text(result.summary.grade, 140, finalY + 12);

  doc.setFont('helvetica', 'normal');
  doc.text('Result Status:', 110, finalY + 22);
  doc.setFont('helvetica', 'bold');
  doc.setTextColor(result.summary.status === 'Pass' ? [21, 128, 61] : [185, 28, 28]);
  doc.text(result.summary.status.toUpperCase(), 140, finalY + 22);

  // -- Footer Section --
  const footerY = 270;
  doc.setDrawColor(226, 232, 240);
  doc.line(20, footerY, pageWidth - 20, footerY);

  doc.setTextColor(148, 163, 184);
  doc.setFontSize(9);
  doc.setFont('helvetica', 'normal');
  doc.text(`Date of Issue: ${new Date().toLocaleDateString()}`, 20, footerY + 7);

  doc.setTextColor(71, 85, 105);
  doc.setFontSize(10);
  doc.setFont('helvetica', 'bold');
  doc.text('Principal Signature', pageWidth - 60, footerY + 15);
  doc.line(pageWidth - 65, footerY + 10, pageWidth - 25, footerY + 10);

  // Watermark (Optional simple text watermark)
  doc.setTextColor(241, 245, 249);
  doc.setFontSize(60);
  doc.setFont('helvetica', 'bold');
  doc.text(config.name, pageWidth / 2, pageWidth / 2 + 50, { align: 'center', angle: 45 });
};

