                    </td>
                    <td className="px-6 py-4">
                      <span className={`px-3 py-1 rounded-full text-xs font-black ${
                        res.summary.grade === 'A+' ? 'bg-purple-100 text-purple-700' :
                        res.summary.grade === 'A' ? 'bg-blue-100 text-blue-700' :
