export default ResultDisplay;

import { jsPDF } from 'jspdf';
import autoTable from 'jspdf-autotable';
import { ProcessedResult, SchoolConfig } from '../types';

/**
 * Utility to ensure a value is a valid number for jsPDF coordinates.
 * Prevents the common 'Invalid argument passed to jsPDF.f3' error.
 */
const safeNum = (val: any, fallback: number = 0): number => {
  const n = Number(val);
  return isNaN(n) ? fallback : n;
};

export const generateSinglePDF = async (result: ProcessedResult, config: SchoolConfig, shouldPrint: boolean = false) => {
  const doc = new jsPDF({
    orientation: 'portrait',
    unit: 'mm',
    format: 'a4'
  });

  addResultCardToDoc(doc, result, config);

  if (shouldPrint) {
    doc.autoPrint();
    window.open(doc.output('bloburl'), '_blank');
  } else {
    doc.save(`${result.student.rollNo}_${result.student.name.replace(/\s+/g, '_')}_Result.pdf`);
  }
};

export const generateBulkPDF = async (results: ProcessedResult[], config: SchoolConfig, shouldPrint: boolean = false) => {
  const doc = new jsPDF({
    orientation: 'portrait',
    unit: 'mm',
    format: 'a4'
  });

  results.forEach((result, index) => {
    if (index > 0) doc.addPage();
    addResultCardToDoc(doc, result, config);
  });

  if (shouldPrint) {
    doc.autoPrint();
    window.open(doc.output('bloburl'), '_blank');
  } else {
    doc.save(`${config.name.replace(/\s+/g, '_')}_Full_Results.pdf`);
  }
};

const addResultCardToDoc = (doc: jsPDF, result: ProcessedResult, config: SchoolConfig) => {
  const pageWidth = safeNum(doc.internal.pageSize.getWidth(), 210);

  // -- Aesthetic Accent --
  doc.setFillColor(30, 64, 175); // Deeper blue
  doc.rect(0, 0, pageWidth, 4, 'F');

  // -- Header Section --
  doc.setFillColor(248, 250, 252); // Very light slate
  doc.rect(0, 4, pageWidth, 46, 'F');

  doc.setTextColor(30, 58, 138); // Blue 900
  doc.setFont('helvetica', 'bold');
  doc.setFontSize(26);
  doc.text(String(config.name || '').toUpperCase(), pageWidth / 2, 22, { align: 'center' });

  doc.setTextColor(71, 85, 105); // Slate 600
  doc.setFontSize(9);
  doc.setFont('helvetica', 'normal');
  doc.text(String(config.address || ''), pageWidth / 2, 28, { align: 'center' });
  doc.text(`Contact: ${String(config.contact || '')}`, pageWidth / 2, 33, { align: 'center' });

  doc.setTextColor(30, 64, 175); // Blue 800
  doc.setFontSize(14);
  doc.setFont('helvetica', 'bold');
  doc.text(String(config.examType || ''), pageWidth / 2, 44, { align: 'center' });

  // -- Student Information Grid --
  let currentY = 65;
  doc.setDrawColor(226, 232, 240);
  doc.line(20, currentY - 5, pageWidth - 20, currentY - 5);

  doc.setFontSize(10);
  doc.setTextColor(100, 116, 139); // Slate 500

  const leftCol = 25;
  const rightCol = 115;

  // Student details with labels
  const drawInfo = (label: string, value: string, x: number, y: number) => {
    doc.setFont('helvetica', 'normal');
    doc.setTextColor(100, 116, 139);
    doc.text(label, x, y);
    doc.setFont('helvetica', 'bold');
    doc.setTextColor(30, 41, 59);
    doc.text(String(value || ''), x + 35, y);
  };

  drawInfo('Roll Number:', result.student.rollNo, leftCol, currentY);
  drawInfo('Class/Section:', `${result.student.class} - ${result.student.section}`, rightCol, currentY);

  currentY += 8;
  drawInfo('Student Name:', result.student.name, leftCol, currentY);
  drawInfo('Father Name:', result.student.fatherName, rightCol, currentY);

  currentY += 8;
  drawInfo('Date of Birth:', result.student.dob, leftCol, currentY);
  drawInfo('Academic Year:', config.academicYear, rightCol, currentY);

  // -- Marks Table --
  autoTable(doc, {
    startY: currentY + 12,
    margin: { left: 20, right: 20 },
    head: [['SUBJECT NAME', 'TOTAL', 'PASSING', 'OBTAINED', 'STATUS']],
    body: result.scores.map(s => [
      String(s.subjectName || '').toUpperCase(),
      String(s.totalMarks || '0'),
      String(s.passingMarks || '0'),
      String(s.obtainedMarks || '0'),
      Number(s.obtainedMarks) >= Number(s.passingMarks) ? 'PASS' : 'FAIL'
    ]),
    theme: 'grid',
    headStyles: { 
      fillColor: [30, 64, 175], 
      textColor: 255, 
      halign: 'center', 
      fontStyle: 'bold',
      fontSize: 9,
      cellPadding: 3
    },
    columnStyles: {
      0: { halign: 'left', fontStyle: 'bold', cellWidth: 'auto' },
      1: { halign: 'center', cellWidth: 25 },
      2: { halign: 'center', cellWidth: 25 },
      3: { halign: 'center', cellWidth: 25 },
      4: { halign: 'center', cellWidth: 25 }
    },
    bodyStyles: { 
      textColor: [51, 65, 85],
      fontSize: 9,
      cellPadding: 3
    },
    didParseCell: (data) => {
      if (data.section === 'body' && data.column.index === 4) {
        if (data.cell.text[0] === 'FAIL') {
          data.cell.styles.textColor = [185, 28, 28]; // Red 700
          data.cell.styles.fontStyle = 'bold';
        } else {
          data.cell.styles.textColor = [21, 128, 61]; // Green 700
          data.cell.styles.fontStyle = 'bold';
        }
      }
    }
  });

  const autoTableResults = (doc as any).lastAutoTable;
  let finalY = safeNum(autoTableResults?.finalY, currentY + 60) + 10;

  // -- Summary & Performance Box --
  const boxWidth = pageWidth - 40;
  doc.setFillColor(248, 250, 252);
  doc.rect(20, finalY, boxWidth, 40, 'F');
  doc.setDrawColor(203, 213, 225);
  doc.rect(20, finalY, boxWidth, 40, 'S');

  // Vertical Divider
  doc.line(pageWidth / 2, finalY + 5, pageWidth / 2, finalY + 35);

  doc.setTextColor(100, 116, 139);
  doc.setFontSize(9);

  // Left Side Summary
  doc.text('TOTAL MARKS OBTAINED', 30, finalY + 12);
  doc.setFontSize(14);
  doc.setTextColor(30, 41, 59);
  doc.setFont('helvetica', 'bold');
  doc.text(`${result.summary.totalObtainedMarks} / ${result.summary.totalMaxMarks}`, 30, finalY + 20);

  doc.setFontSize(9);
  doc.setTextColor(100, 116, 139);
  doc.text('PERCENTAGE', 30, finalY + 30);
  doc.setFontSize(14);
  doc.setTextColor(30, 41, 59);
  doc.text(`${result.summary.percentage}%`, 30, finalY + 37);

  // Right Side Summary
  doc.setFontSize(9);
  doc.setTextColor(100, 116, 139);
  doc.text('FINAL GRADE', pageWidth / 2 + 10, finalY + 12);
  doc.setFontSize(22);
  doc.setTextColor(30, 64, 175);
  doc.setFont('helvetica', 'bold');
  doc.text(String(result.summary.grade || ''), pageWidth / 2 + 10, finalY + 22);

  doc.setFontSize(9);
  doc.setTextColor(100, 116, 139);
  doc.text('RESULT STATUS', pageWidth / 2 + 10, finalY + 32);

  const statusColor = result.summary.status === 'Pass' ? [21, 128, 61] : [185, 28, 28];
  doc.setTextColor(statusColor[0], statusColor[1], statusColor[2]);
  doc.setFontSize(14);
  doc.text(String(result.summary.status || '').toUpperCase(), pageWidth / 2 + 10, finalY + 38);

  // -- Signature Section --
  const footerY = 265;
  doc.setDrawColor(226, 232, 240);
  doc.line(20, footerY, pageWidth - 20, footerY);

  doc.setTextColor(148, 163, 184);
  doc.setFontSize(8);
  doc.setFont('helvetica', 'normal');
  doc.text(`Generated on: ${new Date().toLocaleString()}`, 20, footerY + 5);
  doc.text(`© ${config.name} - Official Result Document`, pageWidth / 2, footerY + 5, { align: 'center' });

  doc.setTextColor(71, 85, 105);
  doc.setFontSize(10);
  doc.setFont('helvetica', 'bold');
  doc.text('Authorized Signature', pageWidth - 60, footerY + 18);
  doc.line(pageWidth - 65, footerY + 14, pageWidth - 15, footerY + 14);
};

