const addResultCardToDoc = (doc: jsPDF, result: ProcessedResult, config: SchoolConfig) => {
  const pageWidth = safeNum(doc.internal.pageSize.getWidth(), 210);

  // -- Modern Brand Palette --
  const colors = {
    primary: [49, 46, 129],    // Indigo 900
    secondary: [79, 70, 229],  // Indigo 600
    accent: [245, 158, 11],    // Amber 500
    success: [5, 150, 105],    // Emerald 600
    danger: [225, 29, 72],     // Rose 600
    slate: [71, 85, 105],      // Slate 600
    bg: [248, 250, 252],       // Slate 50
    border: [226, 232, 240]    // Slate 200
  };

  // -- Top Header Accent --
  doc.setFillColor(colors.primary[0], colors.primary[1], colors.primary[2]);
  doc.rect(0, 0, pageWidth, 5, 'F');

  // -- Header Section --
  doc.setFillColor(colors.bg[0], colors.bg[1], colors.bg[2]);
  doc.rect(0, 5, pageWidth, 45, 'F');

  doc.setTextColor(colors.primary[0], colors.primary[1], colors.primary[2]);
  doc.setFont('helvetica', 'bold');
  doc.setFontSize(28);
  doc.text(String(config.name || '').toUpperCase(), pageWidth / 2, 24, { align: 'center' });

  doc.setTextColor(colors.slate[0], colors.slate[1], colors.slate[2]);
  doc.setFontSize(10);
  doc.setFont('helvetica', 'normal');
  doc.text(String(config.address || ''), pageWidth / 2, 31, { align: 'center' });
  doc.text(`Contact: ${String(config.contact || '')}`, pageWidth / 2, 36, { align: 'center' });

  doc.setTextColor(colors.secondary[0], colors.secondary[1], colors.secondary[2]);
  doc.setFontSize(14);
  doc.setFont('helvetica', 'bold');
  doc.text(String(config.examType || '').toUpperCase(), pageWidth / 2, 45, { align: 'center' });

  // -- Student Information Section --
  let currentY = 65;
  doc.setDrawColor(colors.border[0], colors.border[1], colors.border[2]);
  doc.line(20, currentY - 5, pageWidth - 20, currentY - 5);

  const leftCol = 25;
  const rightCol = 115;

  const drawLabelValue = (label: string, value: string, x: number, y: number) => {
    doc.setFontSize(9);
    doc.setFont('helvetica', 'normal');
    doc.setTextColor(148, 163, 184); // Light slate
    doc.text(label.toUpperCase(), x, y);

    doc.setFontSize(11);
    doc.setFont('helvetica', 'bold');
    doc.setTextColor(30, 41, 59); // Slate 900
    doc.text(String(value || '-'), x, y + 5);
  };

  drawLabelValue('Roll Number', result.student.rollNo, leftCol, currentY);
  drawLabelValue('Class / Section', `${result.student.class} - ${result.student.section}`, rightCol, currentY);

  currentY += 15;
  drawLabelValue('Student Name', result.student.name, leftCol, currentY);
  drawLabelValue('Father Name', result.student.fatherName, rightCol, currentY);

  currentY += 15;
  drawLabelValue('Date of Birth', result.student.dob, leftCol, currentY);
  drawLabelValue('Academic Session', config.academicYear, rightCol, currentY);

  // -- Performance Table --
  autoTable(doc, {
    startY: currentY + 15,
    margin: { left: 20, right: 20 },
    head: [['SUBJECT', 'MAX MARKS', 'PASSING', 'OBTAINED', 'REMARKS']],
    body: result.scores.map(s => [
      String(s.subjectName || '').toUpperCase(),
      String(s.totalMarks || '0'),
      String(s.passingMarks || '0'),
      String(s.obtainedMarks || '0'),
      Number(s.obtainedMarks) >= Number(s.passingMarks) ? 'PASS' : 'FAIL'
    ]),
    theme: 'grid',
    headStyles: { 
      fillColor: colors.primary, 
      textColor: 255, 
      halign: 'center', 
      fontStyle: 'bold',
      fontSize: 10,
      cellPadding: 4
    },
    columnStyles: {
      0: { halign: 'left', fontStyle: 'bold' },
      1: { halign: 'center' },
      2: { halign: 'center' },
      3: { halign: 'center' },
      4: { halign: 'center' }
    },
    bodyStyles: { 
      textColor: [51, 65, 85],
      fontSize: 10,
      cellPadding: 4
    },
    didParseCell: (data) => {
      if (data.section === 'body' && data.column.index === 4) {
        if (data.cell.text[0] === 'FAIL') {
          data.cell.styles.textColor = colors.danger;
          data.cell.styles.fontStyle = 'bold';
        } else {
          data.cell.styles.textColor = colors.success;
          data.cell.styles.fontStyle = 'bold';
        }
      }
    }
  });

  const autoTableResults = (doc as any).lastAutoTable;
  let finalY = safeNum(autoTableResults?.finalY, currentY + 70) + 12;

  // -- Result Summary Card --
  const cardWidth = pageWidth - 40;
  const cardHeight = 45;

  // Outer shadow-like border
  doc.setDrawColor(colors.border[0], colors.border[1], colors.border[2]);
  doc.setFillColor(255, 255, 255);
  // jsPDF doesn't have native roundedRect in all versions easily, rect is safer for generic builds but let's try rounded
  try {
    (doc as any).roundedRect(20, finalY, cardWidth, cardHeight, 3, 3, 'FD');
  } catch(e) {
    doc.rect(20, finalY, cardWidth, cardHeight, 'FD');
  }

  // Vertical Separator
  doc.setDrawColor(colors.border[0], colors.border[1], colors.border[2]);
  doc.line(pageWidth / 2, finalY + 8, pageWidth / 2, finalY + cardHeight - 8);

  // Left Section: Numeric Stats
  doc.setFontSize(9);
  doc.setTextColor(148, 163, 184);
  doc.setFont('helvetica', 'bold');
  doc.text('AGGREGATE MARKS', 30, finalY + 12);

  doc.setFontSize(18);
  doc.setTextColor(30, 41, 59);
  doc.text(`${result.summary.totalObtainedMarks} / ${result.summary.totalMaxMarks}`, 30, finalY + 22);

  doc.setFontSize(9);
  doc.setTextColor(148, 163, 184);
  doc.text('PERCENTAGE SCORE', 30, finalY + 32);

  doc.setFontSize(18);
  doc.setTextColor(colors.secondary[0], colors.secondary[1], colors.secondary[2]);
  doc.text(`${result.summary.percentage}%`, 30, finalY + 40);

  // Right Section: Grade & Status
  doc.setFontSize(9);
  doc.setTextColor(148, 163, 184);
  doc.text('FINAL GRADE', pageWidth / 2 + 10, finalY + 12);

  doc.setFontSize(28);
  doc.setTextColor(colors.primary[0], colors.primary[1], colors.primary[2]);
  doc.text(String(result.summary.grade || '-'), pageWidth / 2 + 10, finalY + 24);

  doc.setFontSize(9);
  doc.setTextColor(148, 163, 184);
  doc.text('RESULT STATUS', pageWidth / 2 + 10, finalY + 34);

  const isPass = result.summary.status === 'Pass';
  doc.setTextColor(isPass ? colors.success[0] : colors.danger[0], isPass ? colors.success[1] : colors.danger[1], isPass ? colors.success[2] : colors.danger[2]);
  doc.setFontSize(14);
  doc.text(String(result.summary.status || '').toUpperCase(), pageWidth / 2 + 10, finalY + 41);

  // -- Footer Branding --
  const footerY = 275;
  doc.setDrawColor(colors.border[0], colors.border[1], colors.border[2]);
  doc.line(20, footerY, pageWidth - 20, footerY);

  doc.setTextColor(148, 163, 184);
  doc.setFontSize(8);
  doc.setFont('helvetica', 'normal');
  doc.text(`Certificate No: EPS-${result.student.rollNo}-${new Date().getFullYear()}`, 20, footerY + 5);
  doc.text(`Printed: ${new Date().toLocaleString()}`, pageWidth - 20, footerY + 5, { align: 'right' });

  // -- Signature Block --
  const sigY = 255;
  doc.setTextColor(30, 41, 59);
  doc.setFontSize(10);
  doc.setFont('helvetica', 'bold');
  doc.text('Principal / Headmaster', pageWidth - 60, sigY + 10);
  doc.setDrawColor(30, 41, 59);
  doc.line(pageWidth - 65, sigY + 5, pageWidth - 15, sigY + 5);
};

import React, { useState, useRef } from 'react';
import * as XLSX from 'xlsx';
import { Upload, FileSpreadsheet, X, AlertCircle, Loader2, CheckCircle2 } from 'lucide-react';
import { StudentInfo, SubjectScore, ProcessedResult } from '../types';
import { processResults } from '../utils/calculations';

interface Props {
  onComplete: (results: ProcessedResult[]) => void;
}

const FileUploader: React.FC<Props> = ({ onComplete }) => {
  const [isUploading, setIsUploading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [fileName, setFileName] = useState<string | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Helper to handle Excel numeric dates
  const formatExcelDate = (val: any): string => {
    if (typeof val === 'number') {
      const date = XLSX.SSF.parse_date_code(val);
      const d = String(date.d).padStart(2, '0');
      const m = String(date.m).padStart(2, '0');
      const y = date.y;
      return `${d}-${m}-${y}`;
    }
    return String(val || '');
  };

  const validateAndProcess = (data: any) => {
    try {
      const studentSheet = data['Student Information'];
      const marksSheet = data['Subjects and Marks'];

      if (!studentSheet || !marksSheet) {
        throw new Error('Required sheets ("Student Information" and "Subjects and Marks") are missing.');
      }

      // Convert sheets to JSON
      const students: StudentInfo[] = XLSX.utils.sheet_to_json(studentSheet).map((row: any) => ({
        rollNo: String(row['Roll No (Required)'] || row['Roll No'] || ''),
        name: String(row['Student Name'] || ''),
        fatherName: String(row['Father Name'] || ''),
        dob: formatExcelDate(row['Date of Birth (DD-MM-YYYY)'] || row['Date of Birth']),
        class: String(row['Class'] || ''),
        section: String(row['Section'] || '')
      }));

      const scores: SubjectScore[] = XLSX.utils.sheet_to_json(marksSheet).map((row: any) => ({
        rollNo: String(row['Roll No'] || ''),
        subjectName: String(row['Subject Name'] || ''),
        totalMarks: Number(row['Total Marks'] || 0),
        obtainedMarks: Number(row['Obtained Marks'] || 0),
        passingMarks: Number(row['Passing Marks'] || 0)
      }));

      // Basic validation
      if (students.length === 0) throw new Error('No student records found.');
      if (scores.length === 0) throw new Error('No subject marks found.');

      const processed = processResults(students, scores);
      onComplete(processed);
    } catch (err: any) {
      setError(err.message || 'Error processing the file. Please check the template format.');
      setIsUploading(false);
    }
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setFileName(file.name);
    setError(null);
    setIsUploading(true);

    const reader = new FileReader();
    reader.onload = (evt) => {
      const bstr = evt.target?.result;
      const wb = XLSX.read(bstr, { type: 'binary' });
      const data: any = {};
      wb.SheetNames.forEach(name => {
        data[name] = wb.Sheets[name];
      });

      // Simulate slight delay for smooth UI feel
      setTimeout(() => {
        validateAndProcess(data);
      }, 800);
    };
    reader.onerror = () => {
      setError('Failed to read the file.');
      setIsUploading(false);
    };
    reader.readAsBinaryString(file);
  };

  const triggerInput = () => {
    fileInputRef.current?.click();
  };

  const reset = () => {
    setFileName(null);
    setError(null);
    setIsUploading(false);
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  return (
    <div className="bg-white rounded-2xl shadow-sm border border-slate-200 overflow-hidden animate-in fade-in slide-in-from-bottom-4 duration-500">
      <div className="p-8 border-b border-slate-100">
        <h2 className="text-2xl font-bold text-slate-800">Upload Student Data</h2>
        <p className="text-slate-500 mt-1">Upload the filled Excel template to generate results.</p>
      </div>

      <div className="p-8">
        {!isUploading && !error && !fileName && (
          <div 
            onClick={triggerInput}
            className="border-2 border-dashed border-slate-200 rounded-3xl bg-slate-50 p-12 flex flex-col items-center justify-center cursor-pointer hover:border-blue-400 hover:bg-blue-50 transition-all group"
          >
            <div className="bg-white p-6 rounded-full shadow-sm mb-6 group-hover:scale-110 transition-transform">
              <Upload className="w-12 h-12 text-blue-600" />
            </div>
            <h3 className="text-xl font-bold text-slate-800 mb-2">Drop your Excel file here</h3>
            <p className="text-slate-500 mb-8">or click to browse your computer</p>
            <span className="text-xs font-semibold text-slate-400 uppercase tracking-widest">Supported formats: .xlsx, .xls</span>
            <input 
              ref={fileInputRef}
              type="file" 
              accept=".xlsx, .xls" 
              className="hidden" 
              onChange={handleFileUpload} 
            />
          </div>
        )}

        {isUploading && !error && (
          <div className="py-20 flex flex-col items-center justify-center">
            <Loader2 className="w-16 h-16 text-blue-600 animate-spin mb-6" />
            <h3 className="text-xl font-bold text-slate-800 mb-2">Processing Data...</h3>
            <p className="text-slate-500">Parsing sheets and calculating results</p>
          </div>
        )}

        {error && (
          <div className="p-8 border-2 border-red-100 bg-red-50 rounded-3xl flex flex-col items-center text-center">
            <div className="bg-red-100 p-4 rounded-full mb-6">
              <AlertCircle className="w-10 h-10 text-red-600" />
            </div>
            <h3 className="text-xl font-bold text-red-900 mb-2">Upload Failed</h3>
            <p className="text-red-800 mb-8 max-w-md">{error}</p>
            <button 
              onClick={reset}
              className="px-8 py-3 bg-red-600 text-white font-bold rounded-xl hover:bg-red-700 transition-colors"
            >
              Try Another File
            </button>
          </div>
        )}
      </div>
    </div>
  );
};

export default FileUploader;

import { jsPDF } from 'jspdf';
import autoTable from 'jspdf-autotable';
import { ProcessedResult, SchoolConfig } from '../types';

/**
 * Utility to ensure a value is a valid number for jsPDF coordinates.
 * Prevents the common 'Invalid argument passed to jsPDF.f3' error.
 */
const safeNum = (val: any, fallback: number = 0): number => {
  const n = Number(val);
  return isNaN(n) ? fallback : n;
};

export const generateSinglePDF = async (result: ProcessedResult, config: SchoolConfig, shouldPrint: boolean = false) => {
  const doc = new jsPDF({
    orientation: 'portrait',
    unit: 'mm',
    format: 'a4'
  });

  addResultCardToDoc(doc, result, config);

  if (shouldPrint) {
    doc.autoPrint();
    window.open(doc.output('bloburl'), '_blank');
  } else {
    doc.save(`${result.student.rollNo}_${result.student.name.replace(/\s+/g, '_')}_Result.pdf`);
  }
};

export const generateBulkPDF = async (results: ProcessedResult[], config: SchoolConfig, shouldPrint: boolean = false) => {
  const doc = new jsPDF({
    orientation: 'portrait',
    unit: 'mm',
    format: 'a4'
  });

  results.forEach((result, index) => {
    if (index > 0) doc.addPage();
    addResultCardToDoc(doc, result, config);
  });

  if (shouldPrint) {
    doc.autoPrint();
    window.open(doc.output('bloburl'), '_blank');
  } else {
    doc.save(`${config.name.replace(/\s+/g, '_')}_Full_Results.pdf`);
  }
};

const addResultCardToDoc = (doc: jsPDF, result: ProcessedResult, config: SchoolConfig) => {
  const pageWidth = safeNum(doc.internal.pageSize.getWidth(), 210);

  // -- Modern Brand Palette --
  const colors = {
    primary: [49, 46, 129],    // Indigo 900
    secondary: [79, 70, 229],  // Indigo 600
    accent: [245, 158, 11],    // Amber 500
    success: [5, 150, 105],    // Emerald 600
    danger: [225, 29, 72],     // Rose 600
    slate: [71, 85, 105],      // Slate 600
    bg: [248, 250, 252],       // Slate 50
    border: [226, 232, 240],   // Slate 200
    textMain: [30, 41, 59],    // Slate 900
    textMuted: [148, 163, 184] // Slate 400
  };

  // -- Top Header Accent --
  doc.setFillColor(colors.primary[0], colors.primary[1], colors.primary[2]);
  doc.rect(0, 0, pageWidth, 4, 'F');

  // -- Header Section --
  doc.setFillColor(colors.bg[0], colors.bg[1], colors.bg[2]);
  doc.rect(0, 4, pageWidth, 42, 'F');

  doc.setTextColor(colors.primary[0], colors.primary[1], colors.primary[2]);
  doc.setFont('helvetica', 'bold');
